return items.map(item => {

  // 1. ACCESS THE VARIABLE
  // In n8n, the incoming webhook payload is usually inside 'item.json'
  // We want the 'body' property where Airtable data lives.
  const rawBody = item.json.body;  

  // 2. HELPER: Number Converter
  // Converts "$11.00" strings to actual numbers (11.00)
  const parseCurrency = (value) => {
    if (typeof value === 'string' && value.includes('$')) {
        return parseFloat(value.replace('$', '').replace(',', ''));
    }
    return value;
  };

  // 3. CONSTRUCT OUTPUT
  // We return the clean structure inside the 'json' property required by n8n
  return {
    json: {

      ...rawBody,


      // This keeps the original strings (e.g. "$11.00") but adds 
      // usable numbers for any math nodes you might use later.
      clientRate_num: parseCurrency(rawBody.clientRate),
      clientOtRate_num: parseCurrency(rawBody.clientOtRate),
      svBaseRate_num: parseCurrency(rawBody.svBaseRate),
      svOtRate_num: parseCurrency(rawBody.svOtRate),


    }
  };
});
